```PREFIX dbo: <http://dbpedia.org/ontology/>
PREFIX dbr: <http://dbpedia.org/resource/>

SELECT DISTINCT ?mountain WHERE {
  ?mountain a dbo:Mountain ;
            dbo:elevation ?elevation .
  {
    # Highest mountain in Saxony Germany
    ?mountain dbo:location ?location .
    ?location dbo:isPartOf dbr:Saxony .
    ?location dbo:isPartOf* dbr:Germany .
  }
  UNION
  {
    # Highest mountain anywhere (no location restriction)
    FILTER NOT EXISTS {
      ?mountain dbo:location ?loc .
    }
  }
}
ORDER BY DESC(?elevation)
LIMIT 1
```

```PREFIX dbo: <http://dbpedia.org/ontology/> 
PREFIX res: <http://dbpedia.org/resource/> 

SELECT ?answer WHERE {
  { 
    BIND("Was U.S. president Jackson involved in a war?" AS ?question) 
    BIND(IF(EXISTS { res:Andrew_Jackson dbo:battle ?battle }, "yes", "no") AS ?answer) 
  } UNION { 
    BIND("Which presidents were born in 1945?" AS ?question) 
    ?answer a dbo:President ;
            dbo:birthDate ?date .
    FILTER STRSTARTS(STR(?date), "1945")
  } UNION {
    BIND("Who was John F. Kennedy's vice president?" AS ?question) 
    res:John_F._Kennedy dbo:vicePresident ?answer 
  }
}
```

```PREFIX dbo: <http://dbpedia.org/ontology/>
PREFIX dbp: <http://dbpedia.org/property/>
PREFIX res: <http://dbpedia.org/resource/>

SELECT DISTINCT ?governor ?timBurtonFilm ?borough WHERE {
  {
    res:Wyoming dbp:governor ?governor .
  }
  UNION
  {
    ?timBurtonFilm dbo:director res:Tim_Burton ;
                    dbo:budget ?budget .
  }
  UNION
  {
    ?borough dbo:governmentType <http://dbpedia.org/resource/Borough_(New_York_City)> .
  }
}
ORDER BY DESC(?budget)
LIMIT 5
```

```PREFIX dbo: <http://dbpedia.org/ontology/> 
PREFIX res: <http://dbpedia.org/resource/> 
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#> 

SELECT DISTINCT ?result WHERE { 
  { res:Rachel_Stevens dbo:birthYear ?result } 
  UNION 
  { res:Cat_Stevens dbo:instrument ?result } 
  UNION 
  { ?result a dbo:Song . 
    ?result dbo:artist res:Bruce_Springsteen . 
    ?result dbo:releaseDate ?date . 
    FILTER (?date >= "1980-01-01"^^xsd:date && ?date <= "1990-12-31"^^xsd:date) 
  } 
}
```

```PREFIX dbo: <http://dbpedia.org/ontology/>
PREFIX res: <http://dbpedia.org/resource/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?biggestStadium ?brazilMinRank ?neymarPlaysRealMadrid WHERE {
  {
    SELECT DISTINCT ?biggestStadium WHERE {
      ?biggestStadium rdf:type dbo:Stadium ;
                      dbo:location res:Spain ;
                      dbo:seatingCapacity ?capacity .
    }
    ORDER BY DESC(?capacity)
    LIMIT 1
  }
  {
    SELECT DISTINCT ?brazilMinRank WHERE {
      res:Brazil_national_football_team <http://dbpedia.org/property/fifaMin> ?brazilMinRank .
    }
  }
  {
    BIND (EXISTS {
      res:Neymar dbo:team <http://dbpedia.org/resource/Real_Madrid_C.F.>
    } AS ?neymarPlaysRealMadrid)
  }
}
```

sparql:
PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

SELECT  ?question ?answer
WHERE
  { VALUES ?question { "How many airlines are there?" "How many airlines are members of the Star Alliance?" "What airlines are part of the SkyTeam alliance?" }
      { FILTER ( ?question = "How many airlines are there?" )
        { PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
          PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
          PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
          PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
          PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

          SELECT  (COUNT(DISTINCT ?airline) AS ?answer)
          WHERE
            { ?airline  rdf:type  <http://dbpedia.org/ontology/Airline> }
        }
      }
    UNION
      { FILTER ( ?question = "How many airlines are members of the Star Alliance?" )
        { PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
          PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
          PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
          PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
          PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

          SELECT  (COUNT(DISTINCT ?airline) AS ?answer)
          WHERE
            { ?airline  rdf:type              <http://dbpedia.org/ontology/Airline> ;
                        <http://dbpedia.org/ontology/alliance>  <http://dbpedia.org/resource/Star_Alliance>
            }
        }
      }
    UNION
      { FILTER ( ?question = "What airlines are part of the SkyTeam alliance?" )
        { PREFIX  xsd:  <http://www.w3.org/2001/XMLSchema#>
          PREFIX  rdfs: <http://www.w3.org/2000/01/rdf-schema#>
          PREFIX  rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
          PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
          PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

          SELECT  (GROUP_CONCAT(DISTINCT str(?airline) ; separator=', ') AS ?answer)
          WHERE
            {   { ?airline  rdf:type              <http://dbpedia.org/ontology/Airline> ;
                            <http://dbpedia.org/ontology/alliance>  <http://dbpedia.org/resource/SkyTeam>
                }
              UNION
                { ?airline  <http://dbpedia.org/ontology/Alliance>  <http://dbpedia.org/resource/SkyTeam> ;
                            rdf:type              <http://dbpedia.org/ontology/Airline>
                }
            }
        }
      }
  }

