```PREFIX yago: <http://dbpedia.org/class/yago/>
PREFIX dbp: <http://dbpedia.org/property/>
PREFIX dbo: <http://dbpedia.org/ontology/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT DISTINCT ?stateWithHighestDensity ?albertaAdmissionDate ?mountMcKinleyState WHERE {
  # Which state of the USA has the highest population density?
  {
    SELECT ?stateWithHighestDensity WHERE {
      ?stateWithHighestDensity rdf:type yago:WikicatStatesOfTheUnitedStates ;
                              dbp:densityrank ?rank .
    } ORDER BY ASC(?rank)
      LIMIT 1
  }

  # When was Alberta admitted as province?
  OPTIONAL {
