```PREFIX dbo: <http://dbpedia.org/ontology/>
PREFIX res: <http://dbpedia.org/resource/>
SELECT DISTINCT ?spouseOfTomCruise ?answer WHERE {
  { 
    BIND (res:Rita_Wilson AS ?rita)
    BIND (res:Tom_Hanks AS ?tomHanks)
    BIND (res:Tom_Cruise AS ?tomCruise)
    BIND (res:James_Bond AS ?jamesBond)

    # Is Rita Wilson the wife of Tom Hanks? Ask if Rita Wilson is spouse of Tom Hanks
    OPTIONAL {
      FILTER EXISTS { ?tomHanks dbo:spouse ?rita }
    }

    # Who has Tom Cruise been married to? Select all spouses for Tom Cruise
    OPTIONAL {
      ?spouseOfTomCruise dbo:spouse res:Tom_Cruise .
    }

    # Is James Bond married? Ask if James Bond has any spouse
    OPTIONAL {
      FILTER EXISTS { ?jamesBond dbo:spouse ?anySpouse }
    }

    # We collect answers in separate variables
    BIND (
      IF (EXISTS { ?tomHanks dbo:spouse ?rita }, "yes", "no") AS ?ritaIsWifeOfTomHanks
    )
    BIND (
      IF (EXISTS { ?jamesBond dbo:spouse ?anySpouse }, "yes", "no") AS ?jamesBondMarried
    )
  }
}
LIMIT 100
```

