SELECT ?starring WHERE {
  {
    # First question (boolean)
    BIND (res:Abraham_Lincoln AS ?lincoln)
    ?lincoln dbo:spouse ?spouse .
    ?spouse rdfs:label ?spouseName .
    FILTER (regex(?spouseName, "Mary", "i"))
  }
  UNION
  {
    # Second question
    ?film rdf:type dbo:Film ;
          dbo:country res:Spain ;
          dbo:producer res:Benicio_del_Toro ;
          dbo:starring ?starring .
    ?starring rdf:type dbo:Person .
  }
  UNION
  {
    # Third question (boolean)
    BIND (res:Arnold_Schwarzenegger AS ?arnold)
    ?arnold dbo:almaMater ?alma .
    ?alma rdf:type dbo:University .
  }
}
```

