PREFIX dbo: <http://dbpedia.org/ontology/>
PREFIX dbr: <http://dbpedia.org/resource/>
PREFIX dbp: <http://dbpedia.org/property/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX yago: <http://dbpedia.org/class/yago/>

SELECT ?largestCity ?largestMetroArea ?stateWithHighestPopDensity WHERE {
  # Largest city in America (United States)
  dbr:United_States dbo:largestCity ?largestCity .

  # Largest metropolitan area in Washington state
  dbr:Washington_(state) dbp:largestmetro ?largestMetroArea .

  # State of the USA with the highest population density 
  {
    SELECT ?stateWithHighestPopDensity WHERE {
      ?stateWithHighestPopDensity rdf:type yago:WikicatStatesOfTheUnitedStates ;
                                 dbp:densityrank ?popDensityRank .
    } ORDER BY ASC(?popDensityRank) LIMIT 1
  }
}

